sparql_query:
PREFIX goo:        <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:       <http://example.org/resource#>
PREFIX schema:     <http://schema.org/>
PREFIX xsd:        <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:        <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:       <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?maxOutages ?hasNearbyHurricane (GROUP_CONCAT(DISTINCT STR(?nearbyHurricaneName); separator=", ") AS ?hurricaneNames)
WHERE {
  {
    SELECT (MAX(?num) AS ?maxOutages)
    WHERE {
      ?record a goo:CustomerOutageRecord ;
              goo:representsCounty gokg:LeeCountyFL ;
              goo:recordDateTime ?recordDate ;
              goo:numberOfOutages ?num .
      FILTER (SUBSTR(STR(?recordDate), 1, 10) = "2022-09-28")
    }
  }
  {
    SELECT (COUNT(DISTINCT ?nearbyCyclone) > 0 AS ?hasNearbyHurricane)
    WHERE {
      gokg:LeeCountyFL goo:lat ?countyLat ;
                       goo:lon ?countyLon .
      ?nearbyCyclone a goo:HurricaneEventRecord ;
                     schema:name ?nearbyHurricaneName ;
                     goo:eventStartTime ?start ;
                     goo:eventEndTime ?end ;
                     goo:hasTrackRecord ?track .
      ?track a goo:HurricaneTrackRecord ;
             goo:recordDateTime ?trackDate ;
             goo:lat ?trackLat ;
             goo:lon ?trackLon .
      FILTER (?start < "2022-09-29T00:00:00+00:00"^^xsd:dateTime && ?end >= "2022-09-28T00:00:00+00:00"^^xsd:dateTime)
      FILTER (SUBSTR(STR(?trackDate), 1, 10) = "2022-09-28")
      FILTER (
        ABS(xsd:decimal(?trackLat) - xsd:decimal(?countyLat)) <= 5 &&
        ABS(xsd:decimal(?trackLon) - xsd:decimal(?countyLon)) <= 5
      )
    }
  }
  OPTIONAL {
    gokg:LeeCountyFL goo:lat ?countyLat ;
                     goo:lon ?countyLon .
    ?nearbyCyclone a goo:HurricaneEventRecord ;
                   schema:name ?nearbyHurricaneName ;
                   goo:eventStartTime ?start ;
                   goo:eventEndTime ?end ;
                   goo:hasTrackRecord ?track .
    ?track a goo:HurricaneTrackRecord ;
           goo:recordDateTime ?trackDate ;
           goo:lat ?trackLat ;
           goo:lon ?trackLon .
    FILTER (?start < "2022-09-29T00:00:00+00:00"^^xsd:dateTime && ?end >= "2022-09-28T00:00:00+00:00"^^xsd:dateTime)
    FILTER (SUBSTR(STR(?trackDate), 1, 10) = "2022-09-28")
    FILTER (
      ABS(xsd:decimal(?trackLat) - xsd:decimal(?countyLat)) <= 5 &&
      ABS(xsd:decimal(?trackLon) - xsd:decimal(?countyLon)) <= 5
    )
  }
}
GROUP BY ?maxOutages ?hasNearbyHurricane
